// Helper function to decrypt a string at runtime
static inline char* decrypt_log_string(encrypted_log_string_t enc, const unsigned char* key, size_t key_len) {
    static char buffer[33] = {0};  // 32 + null
    for (int i = 0; i < 32; i++) {
        buffer[i] = enc.data[i] ^ key[i % key_len];
    }
    buffer[31] = '\0';  // Ensure null termination
    return buffer;
}

